func TestTruncateBody(t *testing.T) {
	t.Parallel()

	const maxBytes = 4096

	cases := []struct {
		name        string
		input       []byte
		wantLen     int
		wantHasTail bool
	}{
		{"empty", nil, 0, false},
		{"under cap", []byte("hello"), 5, false},
		{"at cap", bytes.Repeat([]byte("a"), maxBytes), maxBytes, false},
		{"one over cap", bytes.Repeat([]byte("a"), maxBytes+1), maxBytes + 3, true},
		{"huge body", bytes.Repeat([]byte("a"), maxBytes*8), maxBytes + 3, true},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			t.Parallel()
			got := truncateBody(tc.input)
			if len(got) != tc.wantLen {
				t.Fatalf("len = %d, want %d", len(got), tc.wantLen)
			}
			if tc.wantHasTail && !strings.HasSuffix(got, "...") {
				t.Fatalf("want trailing %q", "...")
			}
			if !tc.wantHasTail && strings.HasSuffix(got, "...") {
				t.Fatalf("unexpected trailing %q in %q", "...", got)
			}
		})
	}
}

func TestTruncateBody_UTF8RuneAtBoundary(t *testing.T) {
	t.Parallel()

	// '€' is 3 bytes (0xE2 0x82 0xAC). Place it so the slice at byte 4096 cuts
	// mid-rune; strings.ToValidUTF8 should drop the partial rune cleanly rather
	// than emit U+FFFD or invalid UTF-8.
	prefix := strings.Repeat("a", 4094)
	body := []byte(prefix + "€" + strings.Repeat("b", 100))
	got := truncateBody(body)

	if !utf8.ValidString(got) {
		t.Fatalf("output is not valid UTF-8")
	}
	if strings.ContainsRune(got, utf8.RuneError) {
		t.Fatalf("output contains replacement rune U+FFFD")
	}
	if !strings.HasSuffix(got, "...") {
		t.Fatalf("want trailing %q", "...")
	}
	// Partial rune must be dropped, not replaced: 4094 valid bytes + "...".
	if want := 4094 + 3; len(got) != want {
		t.Fatalf("len = %d, want %d (partial rune should be dropped, not replaced)", len(got), want)
	}
}

func TestGetRefreshesAccessTokenFromRefreshToken(t *testing.T) {
	var tokenCalls int
	var apiCalls int
	var sawRefreshToken string
	var sawClientID string
	var sawClientSecret string

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		switch r.URL.Path {
		case "/token":
			tokenCalls++
			if err := r.ParseForm(); err != nil {
				t.Fatalf("ParseForm: %v", err)
			}
			sawRefreshToken = r.Form.Get("refresh_token")
			sawClientID = r.Form.Get("client_id")
			sawClientSecret = r.Form.Get("client_secret")
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(map[string]any{
				"access_token":  "fresh-access",
				"refresh_token": "rotated-refresh",
				"expires_in":    3600,
			})
		case "/resource":
			apiCalls++
			if got := r.Header.Get("Authorization"); got != "Bearer fresh-access" {
				t.Fatalf("Authorization = %q, want Bearer fresh-access", got)
			}
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte(`{"ok":true}`))
		default:
			http.NotFound(w, r)
		}
	}))
	defer srv.Close()

	cfg := &config.Config{
		BaseURL:      srv.URL,
		TokenURL:     srv.URL + "/token",
		Path:         filepath.Join(t.TempDir(), "config.toml"),
		ClientID:     "client-id",
		ClientSecret: "client-secret",
		RefreshToken: "initial-refresh",
	}
	c := New(cfg, time.Second, 0)
	data, err := c.Get(t.Context(), "/resource", nil)
	if err != nil {
		t.Fatalf("Get returned error: %v", err)
	}
	if string(data) != `{"ok":true}` {
		t.Fatalf("data = %s, want ok JSON", data)
	}
	if tokenCalls != 1 {
		t.Fatalf("tokenCalls = %d, want 1", tokenCalls)
	}
	if apiCalls != 1 {
		t.Fatalf("apiCalls = %d, want 1", apiCalls)
	}
	if sawRefreshToken != "initial-refresh" || sawClientID != "client-id" || sawClientSecret != "client-secret" {
		t.Fatalf("refresh form = refresh:%q client:%q secret:%q", sawRefreshToken, sawClientID, sawClientSecret)
	}
	if cfg.AccessToken != "fresh-access" {
		t.Fatalf("AccessToken = %q, want fresh-access", cfg.AccessToken)
	}
	if cfg.RefreshToken != "rotated-refresh" {
		t.Fatalf("RefreshToken = %q, want rotated-refresh", cfg.RefreshToken)
	}
	dotEnv, err := os.ReadFile(filepath.Join(filepath.Dir(cfg.Path), ".env"))
	if err != nil {
		t.Fatalf("reading .env: %v", err)
	}
	if !strings.Contains(string(dotEnv), "AMAZON_ADS_REFRESH_TOKEN=rotated-refresh") {
		t.Fatalf(".env did not persist rotated refresh token:\n%s", dotEnv)
	}
}

func TestGetRefreshesAndRetriesAfterUnauthorized(t *testing.T) {
	var tokenCalls int
	var apiCalls int

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		switch r.URL.Path {
		case "/token":
			tokenCalls++
			w.Header().Set("Content-Type", "application/json")
			_ = json.NewEncoder(w).Encode(map[string]any{
				"access_token": "retry-access",
				"expires_in":   3600,
			})
		case "/resource":
			apiCalls++
			if apiCalls == 1 {
				if got := r.Header.Get("Authorization"); got != "Bearer stale-access" {
					t.Fatalf("first Authorization = %q, want Bearer stale-access", got)
				}
				http.Error(w, `{"message":"expired"}`, http.StatusUnauthorized)
				return
			}
			if got := r.Header.Get("Authorization"); got != "Bearer retry-access" {
				t.Fatalf("retry Authorization = %q, want Bearer retry-access", got)
			}
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte(`{"ok":true}`))
		default:
			http.NotFound(w, r)
		}
	}))
	defer srv.Close()

	cfg := &config.Config{
		BaseURL:      srv.URL,
		TokenURL:     srv.URL + "/token",
		Path:         filepath.Join(t.TempDir(), "config.toml"),
		ClientID:     "client-id",
		ClientSecret: "client-secret",
		AccessToken:  "stale-access",
		RefreshToken: "stable-refresh",
	}
	c := New(cfg, time.Second, 0)
	data, err := c.Get(t.Context(), "/resource", nil)
	if err != nil {
		t.Fatalf("Get returned error: %v", err)
	}
	if string(data) != `{"ok":true}` {
		t.Fatalf("data = %s, want ok JSON", data)
	}
	if tokenCalls != 1 {
		t.Fatalf("tokenCalls = %d, want 1", tokenCalls)
	}
	if apiCalls != 2 {
		t.Fatalf("apiCalls = %d, want 2", apiCalls)
	}
	if cfg.AccessToken != "retry-access" {
		t.Fatalf("AccessToken = %q, want retry-access", cfg.AccessToken)
	}
	if cfg.RefreshToken != "stable-refresh" {
		t.Fatalf("RefreshToken = %q, want stable-refresh", cfg.RefreshToken)
	}
}

func TestRefreshTokenFailureSurfacesProviderError(t *testing.T) {
	t.Parallel()

	var tokenCalls int
	var apiCalls int
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		switch r.URL.Path {
		case "/token":
			tokenCalls++
			w.Header().Set("Content-Type", "application/json")
			w.WriteHeader(http.StatusUnauthorized)
			_, _ = w.Write([]byte(`{"error":"invalid_grant","error_description":"refresh token expired"}`))
		case "/resource":
			apiCalls++
			w.Header().Set("Content-Type", "application/json")
			_, _ = w.Write([]byte(`{"ok":true}`))
		default:
			http.NotFound(w, r)
		}
	}))
	defer srv.Close()

	cfg := &config.Config{
		BaseURL:      srv.URL,
		TokenURL:     srv.URL + "/token",
		Path:         filepath.Join(t.TempDir(), "config.toml"),
		ClientID:     "client-id",
		ClientSecret: "client-secret",
		RefreshToken: "expired-refresh",
	}
	c := New(cfg, time.Second, 0)
	_, err := c.Get(t.Context(), "/resource", nil)
	if err == nil {
		t.Fatalf("Get returned nil error")
	}
	msg := err.Error()
	if !strings.Contains(msg, "HTTP 401") || !strings.Contains(msg, "invalid_grant") || !strings.Contains(msg, "refresh token expired") {
		t.Fatalf("error = %q, want status and provider error details", msg)
	}
	if tokenCalls != 1 {
		t.Fatalf("tokenCalls = %d, want 1", tokenCalls)
	}
	if apiCalls != 0 {
		t.Fatalf("apiCalls = %d, want 0; request should fail before API call", apiCalls)
	}
}
